## **Lead Scoring Sheet Templates**

[Lead Scoring Template - Lead Scoring Template.csv](Lead%20Scoring/Lead_Scoring_Template_-_Lead_Scoring_Template.csv)

- **Auto-Lead Scoring Google Sheets Script**

    ```jsx
    function onOpen() {
      var ui = SpreadsheetApp.getUi();
      // Create custom menu in Google Sheets
      ui.createMenu('Score My Leads')
          .addItem('Score Leads', 'scoreLeads')
          .addToUi();
    }

    function scoreLeads() {
      var sheet = SpreadsheetApp.getActiveSpreadsheet().getActiveSheet();
      var lastRow = sheet.getLastRow();

      // Prompt user for columns
      var titleCol = SpreadsheetApp.getUi().prompt('Enter the column letter that contains "Job Title"').getResponseText();
      var sizeCol = SpreadsheetApp.getUi().prompt('Enter the column letter that contains "Employee size"').getResponseText();
      var revenueCol = SpreadsheetApp.getUi().prompt('Enter the column letter that contains "Revenue"').getResponseText();

      // Create a new "Total Score" column with specified formatting
      var lastCol = sheet.getLastColumn() + 1;
      sheet.insertColumnAfter(lastCol - 1);
      sheet.getRange(1, lastCol).setValue("Total Score").setBackground("red").setFontColor("white").setFontWeight("bold");

      // Fetch values for processing
      var titleValues = sheet.getRange(titleCol + "2:" + titleCol + lastRow).getValues();
      var sizeValues = sheet.getRange(sizeCol + "2:" + sizeCol + lastRow).getValues();
      var revenueValues = sheet.getRange(revenueCol + "2:" + revenueCol + lastRow).getValues();

      var scores = [];

      // Calculate scores
      for (var i = 0; i < lastRow - 1; i++) {
        var titleScore = getJobTitleScore(titleValues[i][0]);
        var sizeScore = getEmployeeSizeScore(sizeValues[i][0]);
        var revenueScore = getRevenueScore(revenueValues[i][0]);

        var totalScore = titleScore + sizeScore + revenueScore;
        scores.push([totalScore]);
      }

      // Set scores in the "Total Score" column
      sheet.getRange(2, lastCol, lastRow - 1, 1).setValues(scores);
    }

    function getJobTitleScore(title) {
      // Score based on job title (modify as needed)
      if (['founder', 'owner', 'ceo'].indexOf(title.toLowerCase()) >= 0) return 10;
      if (title.toLowerCase() === 'c_suite') return 9;
      if (['director', 'vp'].indexOf(title.toLowerCase()) >= 0) return 7;
      if (title.toLowerCase() === 'head') return 5;
      return 0;
    }

    function getEmployeeSizeScore(size) {
      // Score based on employee size (modify as needed)
      if (size > 500) return 10;
      if (size >= 100 && size <= 500) return 7;
      return 4;
    }

    function getRevenueScore(revenue) {
      // Score based on revenue (modify as needed)
      if (revenue > 10000000) return 10;
      if (revenue >= 5000000 && revenue <= 10000000) return 7;
      return 4;
    }
    ```


